// src/components/payment/Payment.jsx
import { useState, useEffect } from "react";
import './Payment.css';

const AmountForm = ({ amount = 0, transportData, onSuccess, onError }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [paymentData, setPaymentData] = useState(null);
  const [paymentStatus, setPaymentStatus] = useState(null);

  // Auto-submit when amount is provided
  useEffect(() => {
    if (amount && amount >= 10 && amount <= 50000) {
      handleSubmit(amount);
    }
  }, [amount]);

  // Check payment status
  const checkPaymentStatus = async (orderId) => {
    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      const response = await fetch(
        `https://chagans.com/payment/status/${orderId}`,
        {
          headers: {
            "Authorization": `Bearer ${token}`,
          },
        }
      );
      
      const data = await response.json();
      return data;
    } catch (err) {
      console.error("Status check error:", err);
      return null;
    }
  };

  const handleSubmit = async (submitAmount) => {
    if (!submitAmount || submitAmount < 10 || submitAmount > 50000) {
      setError("Amount must be between ₹10 and ₹50,000");
      return;
    }

    setIsLoading(true);
    setError("");
    setPaymentStatus(null);

    try {
      const token = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJfaWQiOiI2NzEwODhmZjM4ZGJhNzhhZDY2YjVmZWIiLCJwaG9uZU51bWJlciI6ODgxMDMwMDcyNCwiZW1haWwiOiJzeTI0MTUyN0BnbWFpbC5jb20iLCJyb2xlIjoiY2hhZ2Fuc0VtcGxveWVlMiIsImxvZ2luSWQiOiJmOGUzOWRhOC03MmQ2LTRmNTUtYWJlMC0xM2Q5YWIxMjJmZTkiLCJpYXQiOjE3NjkxNDM0NDUsImV4cCI6MTc3NjkxOTQ0NX0.Y8_yAqXxKhw7Hijfn5zJkHfWDHqijjRyxDom2XwqzFs";
      
      if (!token) {
        setError("Authentication required. Please login.");
        setIsLoading(false);
        return;
      }

      const response = await fetch(
        `https://chagans.com/payment/addMoneyTen`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json"
          },
          body: JSON.stringify({
            amount: submitAmount, 
            transportData: {
              ...transportData,
              trackingId: `TRK${Math.floor(100000 + Math.random() * 900000)}`,
            },
            mobile: "7983920962",
            apiType: "API",
          }),
        }
      );

      const data = await response.json();
      console.log("Payment response:", data);
      
      if (data.success) {
        setPaymentData(data.data);
        
        // Create form and submit to payment gateway
        const form = document.createElement('form');
        form.method = 'POST';
        form.action = data.data.APIURL;
        
        // Add all payment data as hidden inputs
        Object.entries(data.data).forEach(([key, value]) => {
          if (key !== 'APIURL' && value) {
            const input = document.createElement('input');
            input.type = 'hidden';
            input.name = key.toUpperCase();
            input.value = value;
            form.appendChild(input);
          }
        });
        
        document.body.appendChild(form);
        form.submit();
        
      } else if (data.code === 404) {
        // Payment already processed or not found
        setPaymentStatus({
          type: 'already_processed',
          message: data.message || "Payment already processed"
        });
        setError("This payment has already been processed. Please try again with a new order.");
        
        // Check status if we have order ID
        if (data.data?.ORDER_ID) {
          const status = await checkPaymentStatus(data.data.ORDER_ID);
          console.log("Payment status:", status);
        }
      } else {
        setError(data.message || "Payment failed. Please try again.");
      }
    } catch (err) {
      console.error('Payment error:', err);
      setError("Network error. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="amount-form-container">
      {/* Loading State */}
      {isLoading && (
        <div className="loading-indicator">
          <div className="spinner"></div>
          <p>Processing payment...</p>
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          <div>
            <strong style={{color: '#dc2626'}}>⚠️ Error: </strong>
            {error}
          </div>
          <button 
            onClick={() => {
              setError("");
              setPaymentStatus(null);
              // Go back to payment method selection
              if (onError) onError();
            }}
            style={{
              padding: '5px 15px',
              background: '#6b7280',
              color: 'white',
              border: 'none',
              borderRadius: '4px',
              cursor: 'pointer',
              marginLeft: '10px'
            }}
          >
            Try Again
          </button>
        </div>
      )}

      {/* Already Processed Message */}
      {paymentStatus?.type === 'already_processed' && (
        <div className="warning-message">
          <div style={{textAlign: 'center'}}>
            <span style={{fontSize: '48px', display: 'block', marginBottom: '10px'}}>⚠️</span>
            <h3 style={{margin: '0 0 10px 0', color: '#d97706'}}>Payment Already Processed</h3>
            <p style={{margin: '0 0 20px 0', color: '#666'}}>
              This payment has already been processed or is invalid.
            </p>
            <button 
              onClick={() => {
                setPaymentStatus(null);
                setError("");
                // Go back to COD or retry
                if (onError) onError();
              }}
              style={{
                padding: '10px 30px',
                background: '#d97706',
                color: 'white',
                border: 'none',
                borderRadius: '6px',
                fontSize: '16px',
                cursor: 'pointer'
              }}
            >
              Try Cash on Delivery
            </button>
          </div>
        </div>
      )}

      {/* Redirecting Message */}
      {paymentData && !isLoading && !error && !paymentStatus && (
        <div className="success-message">
          <div className="spinner" style={{margin: '0 auto 15px'}}></div>
          <p style={{fontSize: '16px', marginBottom: '10px'}}>
            ✅ Redirecting to secure payment gateway...
          </p>
          <p style={{fontSize: '12px', color: '#666'}}>
            Please do not close this window
          </p>
        </div>
      )}
    </div>
  );
};

export default AmountForm;
